            )
          }
        ),
        #"SYSTEM_SYSRULES_columnLayout"(
          showWhen: #"SYSTEM_SYSRULES_isPageWidth"({ "DESKTOP", "DESKTOP_WIDE" }),
          contents: {}
        )
      },
      marginAbove: if(
        #"SYSTEM_SYSRULES_isNativeMobile"(),
        "NONE",
        if(
          #"SYSTEM_SYSRULES_isPageWidth"({ "DESKTOP", "DESKTOP_WIDE" }),
          "MORE",
          "STANDARD"
        )
      ),
      spacing: "SPARSE",
      stackWhen: {
        "TABLET_PORTRAIT",
        "PHONE"
      }
    )
  },
  backgroundColor: "#fbfbfb"
)

